DROP TABLE IF EXISTS `scan`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `scan` (
  `scan_id` int(11) NOT NULL AUTO_INCREMENT,
  `app_id` int(11) NOT NULL,
  `baseURL` varchar(255) NOT NULL,
  `maxDepth` int(11) DEFAULT 3,
  `start_time` datetime DEFAULT current_timestamp(),
  `end_time` datetime DEFAULT NULL,
  `status` varchar(50) DEFAULT 'running',
  `vulnerable_count` int(11) DEFAULT 0,
  `user_id` int(11) NOT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`scan_id`),
  KEY `fk_scan_user` (`user_id`),
  KEY `app_id` (`app_id`),
  CONSTRAINT `fk_scan_user` FOREIGN KEY (`user_id`) REFERENCES `systemuser` (`user_id`),
  CONSTRAINT `scan_ibfk_1` FOREIGN KEY (`app_id`) REFERENCES `application` (`app_id`)
) ENGINE=InnoDB AUTO_INCREMENT=74 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
